(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[9313],{603:(e,a,s)=>{"use strict";s.r(a),s.d(a,{data:()=>t});const t={key:"v-466662f0",path:"/sql/table/rollback/",title:"ROLLBACK",lang:"en-US",frontmatter:{},excerpt:"",headers:[],filePathRelative:"sql/table/rollback/README.md",git:{updatedTime:162676698e4,contributors:[]}}},8651:(e,a,s)=>{"use strict";s.r(a),s.d(a,{default:()=>l});const t=(0,s(6252).uE)('<h1 id="rollback" tabindex="-1"><a class="header-anchor" href="#rollback" aria-hidden="true">#</a> ROLLBACK</h1><p>เป็นการยกเลิก database buffer โดยจะกลับมาจุดที่ทำการ COMMIT ก่อนหน้าให้ (เหมือนไม่เกิดอะไรขิ้น)</p><p>ตัวอย่างการเรียก <code>ROLLBACK</code></p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code><span class="token keyword">ROLLBACK</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>หากรันคำสั่งแล้ว การแก้ไขบรรทัดที่ยังไม่ได้ทำการ <code>COMMIT</code> จะถูกยกเลิก และคืนค่าอย่างอัตโนมัติ</p>',5),l={render:function(e,a){return t}}}}]);